import java.util.Scanner;

public class SecureBuffer {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.println("Enter a string (limited to 10 characters):");
        String userInput = scanner.nextLine();

        // Limit the input size to 10 characters
        if(userInput.length() > 10) {
            System.out.println("Input exceeds maximum allowed length of 10 characters.");
            return;
        }

        char[] buffer = new char[10];

        // Copy user input into the buffer with bounds checking
        userInput.getChars(0, Math.min(userInput.length(), buffer.length), buffer, 0);

        System.out.println("Input copied successfully!");
    }
}

### Explanation:
취약유형: Buffer Overflow
